/* VCD dumping functions */
MOD_mkTbViterbiDecoder & mkTbViterbiDecoder_backing(tSimStateHdl simHdl)
{
  static MOD_mkTbViterbiDecoder *instance = NULL;
  if (instance == NULL)
  {
    vcd_set_backing_instance(simHdl, true);
    instance = new MOD_mkTbViterbiDecoder(simHdl, "top", NULL);
    vcd_set_backing_instance(simHdl, false);
  }
  return *instance;
}
void MODEL_mkTbViterbiDecoder::dump_VCD_defs()
{
  (mkTbViterbiDecoder_instance->dump_VCD_defs)(vcd_depth(sim_hdl));
}
void MODEL_mkTbViterbiDecoder::dump_VCD(tVCDDumpType dt)
{
  (mkTbViterbiDecoder_instance->dump_VCD)(dt,
					  vcd_depth(sim_hdl),
					  mkTbViterbiDecoder_backing(sim_hdl));
}
